export default function UserManagementTable() {
  const [users, setUsers] = useState<User[]>([]);
  const [search, setSearch] = useState('');

  useEffect(() => {
    fetch('/api/admin/users', {
      headers: { Authorization: `Bearer ${localStorage.getItem('token')}` },
    })
      .then((res) => res.json())
      .then(setUsers);
  }, []);

  const handleRoleChange = async (userId: string, newRole: string) => {
    await fetch(`/api/admin/users/${userId}/role`, {
      method: 'PATCH',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${localStorage.getItem('token')}`,
      },
      body: JSON.stringify({ role: newRole }),
    });
    setUsers((prev) =>
      prev.map((u) => (u.id === userId ? { ...u, role: newRole as User['role'] } : u))
    );
  };

  const filtered = users.filter(
    (u) => u.name.toLowerCase().includes(search.toLowerCase()) ||
           u.email.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <Paper sx={{ p: 2 }}>
      <TextField
        placeholder="Search users..."
        size="small"
        value={search}
        onChange={(e) => setSearch(e.target.value)}
        sx={{ mb: 2, width: 300 }}
      />
      <TableContainer>
        <Table>
          <TableHead>
            <TableRow>
              <TableCell>Name</TableCell>
              <TableCell>Email</TableCell>
              <TableCell>Role</TableCell>
              <TableCell>Status</TableCell>
              <TableCell>Last Login</TableCell>
              <TableCell>Actions</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {filtered.map((user) => (
              <TableRow key={user.id}>
                <TableCell>{user.name}</TableCell>
                <TableCell>{user.email}</TableCell>
                <TableCell>
                  <Select
                    value={user.role}
                    size="small"
                    onChange={(e) => handleRoleChange(user.id, e.target.value)}
                  >
                    <MenuItem value="admin">Admin</MenuItem>
                    <MenuItem value="user">User</MenuItem>
                    <MenuItem value="viewer">Viewer</MenuItem>
                  </Select>
                </TableCell>
                <TableCell>
                  <Chip
                    label={user.status}
                    color={user.status === 'active' ? 'success' : 'default'}
                    size="small"
                  />
                </TableCell>
                <TableCell>{user.lastLogin}</TableCell>
                <TableCell>
                  <IconButton size="small"><EditIcon /></IconButton>
                  <IconButton size="small" color="error"><DeleteIcon /></IconButton>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </TableContainer>
    </Paper>
  );
}

import secrets
import hashlib
from datetime import datetime
from flask import Blueprint, jsonify, request, g
from ..middleware.auth import require_auth
from ..utils.db import get_db

api_keys_bp = Blueprint("api_keys", __name__, url_prefix="/api/keys")


def hash_key(raw_key: str) -> str:
    """Hash the API key for storage. We never store the raw key."""
    return hashlib.sha256(raw_key.encode()).hexdigest()


@api_keys_bp.route("", methods=["POST"])
@require_auth(allowed_roles=["admin", "user"])
def create_api_key():
    data = request.get_json()
    raw_key = f"sk_live_{secrets.token_hex(24)}"

    record = {
        "id": secrets.token_hex(8),
        "name": data.get("name", "Unnamed key"),
        "key_hash": hash_key(raw_key),
        "prefix": raw_key[:12],          # Store the prefix for display
        "tenant_id": g.current_user["tenant_id"],
        "created_by": g.current_user["user_id"],
        "created_at": datetime.utcnow().isoformat(),
        "last_used": None,
        "revoked": False,
    }
    get_db().insert("api_keys", record)

    # Return the raw key ONCE -- it cannot be retrieved later
    return jsonify({"key": raw_key, "id": record["id"], "name": record["name"]}), 201


@api_keys_bp.route("")
@require_auth(allowed_roles=["admin", "user"])
def list_api_keys():
    tenant_id = g.current_user["tenant_id"]
    keys = get_db().find("api_keys", lambda k: k["tenant_id"] == tenant_id and not k["revoked"])
    # Never return the hash -- only the prefix
    safe_keys = [
        {"id": k["id"], "name": k["name"], "prefix": k["prefix"], "created_at": k["created_at"]}
        for k in keys
    ]
    return jsonify(safe_keys)


@api_keys_bp.route("/<key_id>", methods=["DELETE"])
@require_auth(allowed_roles=["admin", "user"])
def revoke_api_key(key_id):
    tenant_id = g.current_user["tenant_id"]
    count = get_db().update(
        "api_keys",
        lambda k: k["id"] == key_id and k["tenant_id"] == tenant_id,
        {"revoked": True},
    )
    if count == 0:
        return jsonify({"error": "Key not found"}), 404
    return jsonify({"message": "API key revoked"})

